def longest_palindrome_subsequence_with_k_changes(s, k):
    n = len(s)
    dp = {}

    def solve(i, j, changes_left):
        if (i, j, changes_left) in dp:
            return dp[(i, j, changes_left)]

        if i > j:
            return 0
        if i == j:
            return 1

        if s[i] == s[j]:
            dp[(i, j, changes_left)] = 2 + solve(i + 1, j - 1, changes_left)
            return dp[(i, j, changes_left)]
        else:
            if changes_left > 0:
                dp[(i, j, changes_left)] = 2 + solve(i + 1, j - 1, changes_left - 1)
                dp[(i, j, changes_left)] = max(dp[(i, j, changes_left)], solve(i + 1, j, changes_left), solve(i, j - 1, changes_left))
            else:
                dp[(i, j, changes_left)] = max(solve(i + 1, j, changes_left), solve(i, j - 1, changes_left))
            return dp[(i, j, changes_left)]

    return solve(0, n - 1, k)

